// Solution
import React, { useState, useMemo } from 'react';
function Calculator() {
  const [numbers, setNumbers] = useState([1, 2, 3, 4, 5]);
  const sum = useMemo(() => numbers.reduce((a, b) => a + b, 0), [JSON.stringify(numbers)]);
  return (
    <div>
      <p>Sum: {sum}</p>
      <button onClick={() => setNumbers([...numbers])}>Update numbers</button>
    </div>
  );
}
